def _validate_payload(payload):
    """Validates the structure and types of the incoming payload."""
    required_fields = {"job_type", "job_id", "items"}
    if not isinstance(payload, dict):
        return False
    if not required_fields.issubset(payload.keys()):
        return False
    if not isinstance(payload["items"], list):
        return False
    if not isinstance(payload["job_id"], str):
        return False
    
    allowed_job_types = {"data_transform", "aggregation", "export", "cleanup", "notification"}
    if payload["job_type"] not in allowed_job_types:
        return False
    return True


def _process_batch(job_type, job_id, items):
    """Routes and processes batch items based on job type."""
    
    handlers = {
        "data_transform": _handle_data_transform,
        "aggregation": _handle_aggregation,
        "export": _handle_export,
        "cleanup": _handle_cleanup,
        "notification": _handle_notification,
    }
    
    handler = handlers.get(job_type)
    if not handler:
        raise ValueError(f"Unknown job type: {job_type}")
    
    processed = 0
    failed = 0
    errors = []
    
    for item in items:
        try:
            handler(job_id, item)
            processed += 1
        except Exception as e:
            failed += 1
            errors.append({"item": str(item)[:200], "error": str(e)})
            logger.warning(f"Failed to process item in job {job_id}: {e}")
    
    return {
        "job_id": job_id,
        "total": len(items),
        "processed": processed,
        "failed": failed,
        "errors": errors[:10],  # Cap error reporting
        "summary": f"{processed}/{len(items)} succeeded, {failed} failed",
        "completed_at": datetime.utcnow().isoformat(),
    }


