def publish_batch_job(project_id, topic_id, job_type, job_id, items, priority="normal"):
    """Example publisher - use this to send tasks to the queue."""
    from google.cloud import pubsub_v1
    
    publisher = pubsub_v1.PublisherClient()
    topic_path = publisher.topic_path(project_id, topic_id)
    
    # Serialize with JSON (SAFE - no pickle!)
    payload = json.dumps({
        "job_type": job_type,
        "job_id": job_id,
        "items": items,
        "submitted_at": datetime.utcnow().isoformat(),
    }).encode("utf-8")
    
    future = publisher.publish(
        topic_path,
        data=payload,
        priority=priority,
    )
    return future.result()